/**
 * @param {number[]} nums
 * @return {number}
 */
function solve(nums) {
    const n = nums.length;
    if (n < 3) {
        return 0;
    }

    // 1. Calculate the cost C[i] for every potential peak index i (1 <= i <= n-2)
    const costs = new Array(n).fill(0);
    for (let i = 1; i <= n - 2; i++) {
        const requiredValue = Math.max(nums[i - 1], nums[i + 1]) + 1;
        const cost = Math.max(0, requiredValue - nums[i]);
        costs[i] = cost;
    }

    // 2. Determine the maximum possible number of peaks, K_max
    // Potential indices are 1, 2, ..., n-2. Total N' = n-2 indices.
    const N_prime = n - 2;
    const K_max = Math.ceil(N_prime / 2);

    // 3. Dynamic Programming: Minimum cost to achieve exactly k peaks using indices up to i.
    // We use space optimization, tracking only the previous step (i-1).
    const INF = Number.MAX_SAFE_INTEGER;

    // D[k]: Min cost ending at previous index (i-1), where (i-1) WAS selected, having k peaks.
    // S[k]: Min cost ending at previous index (i-1), where (i-1) WAS skipped, having k peaks.

    // Initialize for the state before i=1 (i.e., k=0 peaks, cost 0)
    let D_prev = new Array(K_max + 1).fill(INF);
    let S_prev = new Array(K_max + 1).fill(INF);

    S_prev[0] = 0; // 0 peaks selected up to index 0 (conceptually), cost is 0.

    // Iterate through potential peak indices i = 1 to n-2
    for (let i = 1; i <= N_prime; i++) {
        let D_curr = new Array(K_max + 1).fill(INF);
        let S_curr = new Array(K_max + 1).fill(INF);
        const Ci = costs[i];

        // k represents the target number of peaks achieved so far (up to index i)
        for (let k = 0; k <= K_max; k++) {

            // Case 1: Skip index i (S_curr[k])
            // We inherited k peaks from i-1, regardless of whether i-1 was selected or skipped.
            S_curr[k] = Math.min(D_prev[k], S_prev[k]);

            // Case 2: Select index i (D_curr[k])
            // If we select i, we must have skipped i-1. So we need k-1 peaks from i-1.
            if (k > 0) {
                if (S_prev[k - 1] !== INF) {
                    D_curr[k] = S_prev[k - 1] + Ci;
                }
            }
        }

        // Update previous state for next iteration
        D_prev = D_curr;
        S_prev = S_curr;
    }

    // The answer is the minimum cost to achieve K_max peaks up to index n-2,
    // whether the last index (n-2) was selected or skipped.
    const result = Math.min(D_prev[K_max], S_prev[K_max]);

    return result;
}

